1	export type Cell = [number, number];
2	
3	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
4	
5	const survives = (count: number, isAlive: boolean): boolean =>
6	  count === 3 || (count === 2 && isAlive);
7	
8	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
9	  [-1, -1], [-1, 0], [-1, 1],
10	  [ 0, -1],          [ 0, 1],
11	  [ 1, -1], [ 1, 0], [ 1, 1],
12	];
13	
14	export function nextGeneration(liveCells: Cell[]): Cell[] {
15	  const liveSet = new Set(liveCells.map(cellKey));
16	  const neighborCounts = new Map<string, { cell: Cell; count: number }>();
17	
18	  for (const [x, y] of liveCells) {
19	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
20	      const cell: Cell = [x + dx, y + dy];
21	      const key = cellKey(cell);
22	      const entry = neighborCounts.get(key) ?? { cell, count: 0 };
23	      entry.count++;
24	      neighborCounts.set(key, entry);
25	    }
26	  }
27	
28	  const result: Cell[] = [];
29	  for (const [key, { cell, count }] of neighborCounts) {
30	    if (survives(count, liveSet.has(key))) {
31	      result.push(cell);
32	    }
33	  }
34	  return result;
35	}
36

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("should return an empty array when given an empty array", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent live cells (each has only 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 0], [1, 0]])).toEqual([]);
13	  });
14	  it("should keep a 2x2 block stable (each cell has 3 neighbors)", () => {
15	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result).toHaveLength(4);
18	    expect(result).toEqual(expect.arrayContaining(block));
19	  });
20	  it("should oscillate a vertical blinker to horizontal", () => {
21	    const vertical: [number, number][] = [[0, 0], [0, 1], [0, 2]];
22	    const expected: [number, number][] = [[-1, 1], [0, 1], [1, 1]];
23	    const result = nextGeneration(vertical);
24	    expect(result).toHaveLength(3);
25	    expect(result).toEqual(expect.arrayContaining(expected));
26	  });
27	  it("should bring a dead cell to life when it has exactly 3 neighbors (reproduction)", () => {
28	    const input: [number, number][] = [[0, 0], [1, 0], [0, 1]];
29	    const result = nextGeneration(input);
30	    expect(result).toEqual(expect.arrayContaining([[1, 1] as [number, number]]));
31	  });
32	  it("should kill a live cell with more than 3 neighbors (overpopulation)", () => {
33	    const input: [number, number][] = [
34	      [0, 0], [1, 0], [2, 0],
35	      [0, 1], [1, 1], [2, 1],
36	      [0, 2], [1, 2], [2, 2],
37	    ];
38	    const result = nextGeneration(input);
39	    expect(result).not.toContainEqual([1, 1]);
40	  });
41	  it("should handle negative coordinates correctly", () => {
42	    const input: [number, number][] = [[-1, 0], [0, 0], [1, 0]];
43	    const expected: [number, number][] = [[0, -1], [0, 0], [0, 1]];
44	    const result = nextGeneration(input);
45	    expect(result).toHaveLength(3);
46	    expect(result).toEqual(expect.arrayContaining(expected));
47	  });
48	});
